import { useState } from 'react';
import './App.css';

function App() {
  console[sucsess,setSuc]
  const nosalary = "Select Salary";
  const salary1 = "Less than 15,000k"
  const salary2 = "15,000 to 35,000k"
  const salary3 = "More than 35,000k"

  const [name,setName]=useState("")
  const [age,setAge]=useState(0)
  const [phone,setPhone]=useState(0)
  const[check,setCheck]=useState(false)
  const [salary,setSalary] = useState(nosalary)


  function handleSubmit(){
     if (name.trim() === "") return alert("Enter your name !")
     if (phone.length < 10 && phone.length > 15) return alert("Enter valid Phone number")
     if (age < 18 && age > 80) return alert(" Age not allowed !")
     if (check === true && salary === nosalary ) return alert("Select your salary")
    //  if (salary === nosalary) return alert("Select your salary")
      return alert("Success ✅")



  }



      // if (name.trim() === "" || (phone.length < 10 && phone.length > 15) || (age < 18 || age > 80) )
    //   return alert("Fill the empty input ")
    // else if (name.trim() !== "" && (phone.length > 10 && phone.length < 15) && (age > 18 || age < 80) && check === false)
    //   return alert("Success ✅ ")
    // else if (name.trim() !== "" && (phone.length > 10 && phone.length < 15) && (age > 18 || age < 80) && check === true && salary !== nosalary)
    //   return alert("Success ✅ ")
    // else alert("Select Salary")
  return (
    <div className="App">
      <div className='form'>


        <h2>Request loan for <span>HSBC</span> bank</h2>

        <input type='text' placeholder='Enter Your Name' 
        onChange={(e)=>setName(e.target.value)}></input><br/>

        <input type='text' placeholder='Enter Your Phone Number'
        onChange={(e)=>setPhone(e.target.value)}></input><br/>

        <input type='number' placeholder='Enter Your Age'
        onChange={(e)=>setAge(e.target.value)}></input><br/>

      <div className='check'>
        <input type='checkbox'onClick={(e)=>setCheck(prev => !prev)
}/>
        <label> Aye You have employee?</label>
      </div>

        <select onChange={(e)=>setSalary(e.target.value)}>
          <option >{nosalary}</option>
          <option>{salary1}</option>
          <option>{salary2}</option>
          <option>{salary3}</option>
        </select><br/>

        <button type='submit' onClick={handleSubmit}>Submit</button>


      </div>
            </div>

  );
}

export default App;
